headStyle:
body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
            max-width: 800px;
            margin: 0 auto;
            padding: 20px;
            line-height: 1.6;
            color: #333;
        }
        h1 { color: #2c3e50; border-bottom: 2px solid #3498db; padding-bottom: 10px; }
        .meta {
            background: #ecf0f1;
            padding: 15px;
            border-radius: 5px;
            margin: 20px 0;
            display: flex;
            gap: 20px;
            flex-wrap: wrap;
        }
        .meta span { font-weight: 500; }
        h2 { color: #34495e; margin-top: 30px; border-bottom: 1px solid #eee; padding-bottom: 5px; }
        ul { padding-left: 20px; }
        li { margin: 8px 0; }
        ol { padding-left: 20px; }
        ol li { margin: 15px 0; }
        .portions {
            background: #e8f6f3;
            padding: 20px;
            border-radius: 8px;
            margin: 30px 0;
            border-left: 5px solid #16a085;
        }
        .portions h3 { margin-top: 0; color: #16a085; }
        .notes {
            background: #fef9e7;
            padding: 15px;
            border-radius: 5px;
            margin: 20px 0;
            border-left: 5px solid #f1c40f;
        }
        .back-link {
            display: inline-block;
            margin-top: 30px;
            text-decoration: none;
            color: #3498db;
            font-weight: 500;
        }
        .back-link:hover { text-decoration: underline; }
